#include <stdio.h>
#include <stdlib.h>
#define MAXN 100005
int n, m;
int dist[MAXN][MAXN];
void dfs(int u, int p, int d) {
    for (int v = 0; v < n; v++) {
        if (v != p && dist[u][v] == -1) {
            dist[u][v] = d;
            dfs(v, u, d + 1);
        }
    }
}
int main() {
    scanf("%d", &n);
    for (int i = 0; i < n - 1; i++) {
        int u, v;
        scanf("%d %d", &u, &v);
        dist[u - 1][v - 1] = 1;
        dist[v - 1][u - 1] = 1;
    }
    for (int i = 0; i < n; i++) {
        dfs(i, -1, 0);
    }
    scanf("%d", &m);
    for (int i = 0; i < m; i++) {
        int u, v;
        scanf("%d %d", &u, &v);
        printf("%d\n", dist[u - 1][v - 1]);
    }
    return 0;
}

